  "get_declaration_data": {
    "description": "Retrieves the current metadata and state of a specific import declaration, including line items, current status, and HS codes.",
    "parameters": {
      "type": "object",
      "properties": {
        "declaration_id": {
          "type": "string",
          "description": "The unique ID of the declaration (e.g., DEC-ROO-882)."
        }
      },
      "required": [
        "declaration_id"
      ]
    },
    "example_output": {
      "declaration_id": "DEC-ROO-882",
      "line_items": [
        {
          "hs_code": "8413.70",
          "value": 50000,
          "currency": "USD"
        }
      ],
      "review_status": "PENDING"
    }
  },
  "retrieve_document_content": {
    "description": "Fetches the text content or metadata of supporting documents attached to a declaration, such as the Certificate of Origin (CoO), Invoices, or Bill of Lading.",
    "parameters": {
      "type": "object",
      "properties": {
        "declaration_id": {
          "type": "string",
          "description": "The declaration ID associated with the documents."
        },
        "document_type": {
          "type": "string",
          "enum": [
            "CERTIFICATE_OF_ORIGIN",
            "COMMERCIAL_INVOICE",
            "BILL_OF_LADING",
            "TRANSSHIPMENT_CERTIFICATE"
          ],
          "description": "The type of document to retrieve."
        }
      },
      "required": [
        "declaration_id",
        "document_type"
      ]
    },
    "example_output": {
      "document_id": "DOC-123",
      "content": "HS Code listed: 8413.11. Origin: Country X. Invoiced by: HK Entity...",
      "verification_status": "UNVERIFIED"
    }
  },
  "consult_fta_handbook": {
    "description": "Queries the Handbook on Preferential Rules of Origin for specific Product-Specific Rules (PSR) or consignment requirements (Non-manipulation).",
    "parameters": {
      "type": "object",
      "properties": {
        "fta_name": {
          "type": "string",
          "description": "The name of the Free Trade Agreement."
        },
        "hs_code": {
          "type": "string",
          "description": "The HS code to look up (6-digit level recommended)."
        },
        "topic": {
          "type": "string",
          "enum": [
            "PSR",
            "NON_MANIPULATION",
            "THIRD_PARTY_INVOICING"
          ],
          "description": "The specific regulatory topic to research."
        }
      },
      "required": [
        "fta_name",
        "hs_code",
        "topic"
      ]
    },
    "example_output": {
      "rule_description": "A change to subheading 8413.11-8413.80 from any other heading...",
      "compliance_requirement": "Evidence of customs supervision in transshipment port required."
    }
  },
  "validate_and_record_discrepancy": {
    "description": "Logs an identified discrepancy or validation result into the environment state and updates the validation_errors list.",
    "parameters": {
      "type": "object",
      "properties": {
        "declaration_id": {
          "type": "string",
          "description": "The declaration ID."
        },
        "issue_type": {
          "type": "string",
          "description": "Category of the issue (e.g., HS_CODE_MISMATCH)."
        },
        "description": {
          "type": "string",
          "description": "Detailed explanation of the discrepancy and its resolution."
        },
        "is_resolved": {
          "type": "boolean",
          "description": "Whether the discrepancy has been legally accounted for."
        }
      },
      "required": [
        "declaration_id",
        "issue_type",
        "description",
        "is_resolved"
      ]
    },
    "example_output": null
  },
  "finalize_review": {
    "description": "Updates the total calculated duties and sets the final review status of the declaration.",
    "parameters": {
      "type": "object",
      "properties": {
        "declaration_id": {
          "type": "string",
          "description": "The declaration ID."
        },
        "final_status": {
          "type": "string",
          "enum": [
            "APPROVED",
            "REJECTED"
          ],
          "description": "The final determination for the tariff claim."
        },
        "adjusted_duty_total": {
          "type": "number",
          "description": "The final calculated duty amount after the review."
        }
      },
      "required": [
        "declaration_id",
        "final_status",
        "adjusted_duty_total"
      ]
    },
    "example_output": {
      "status": "SUCCESS",
      "new_state": "APPROVED"
    }
